    if (valor > disponivel) {
        msg.statusCode = 400;
        msg.payload = { ok: false, error: `Valor solicitado (${valor}) excede o disponivel (${disponivel})` };
        return msg;
    }

    const orcRes = await pgReq('GET', `/rest/v1/orcamentos?id=eq.${encodeURIComponent(orcamentoId)}&select=id,cliente_id,numero_da_proposta`, null);
    if (orcRes.statusCode !== 200 || !Array.isArray(orcRes.body) || orcRes.body.length === 0) {
        msg.statusCode = 404;
        msg.payload = { ok: false, error: `Orcamento '${orcamentoId}' not found` };
        return msg;
    }
    const orcamento = orcRes.body[0];

    const novaUtilizacao = {
        credito_id: creditoId,
        orcamento_id: orcamentoId,
        cliente_id: credito.cliente_id || orcamento.cliente_id,
        valor_utilizado: valor,
        tipo_de_utilizacao: 100000000,
        utilizacao_firmada: false,
        utilizacao_cancelada: false,
