    if (createRes.statusCode < 200 || createRes.statusCode >= 300 || !Array.isArray(createRes.body) || createRes.body.length === 0) {
        msg.statusCode = 500;
        const errBody = (createRes.body && (createRes.body.message || createRes.body.error)) || JSON.stringify(createRes.body);
        msg.payload = { ok: false, error: `Failed to create utilizacao: HTTP ${createRes.statusCode} - ${errBody}` };
        return msg;
    }
    const novaUtilId = createRes.body[0].id;

    const novoValorUtilizado = Number(credito.valor_utilizado || 0) + valor;
    const patchRes = await pgReq('PATCH', `/rest/v1/creditos_do_cliente?id=eq.${encodeURIComponent(creditoId)}`, {
        valor_utilizado: novoValorUtilizado,
        updated_at: new Date().toISOString()
    }, { 'Prefer': 'return=representation' });
    if (patchRes.statusCode < 200 || patchRes.statusCode >= 300) {
        await pgReq('DELETE', `/rest/v1/utilizacoes_de_credito?id=eq.${encodeURIComponent(novaUtilId)}`, null);
        msg.statusCode = 500;
        msg.payload = { ok: false, error: `Failed to update credito (rolled back utilizacao): HTTP ${patchRes.statusCode}` };
        return msg;
    }
    const creditoAtualizado = Array.isArray(patchRes.body) && patchRes.body.length > 0 ? patchRes.body[0] : null;

    msg.statusCode = 200;
    msg.payload = {
        ok: true,
        utilizacaoId: novaUtilId,
        valorUtilizado: creditoAtualizado ? creditoAtualizado.valor_utilizado : novoValorUtilizado,
        valorDisponivel: creditoAtualizado ? creditoAtualizado.valor_disponivel : (Number(credito.valor_do_credito || 0) - novoValorUtilizado)
    };
    return msg;
