const portSb = parsedSb.port ? parseInt(parsedSb.port, 10) : (isHttpsSb ? 443 : 80);

function pgReq(method, path, bodyObj, extraHeaders) {
    return new Promise((resolve, reject) => {
        const bodyStr = bodyObj ? JSON.stringify(bodyObj) : null;
        const headers = { 'apikey': SUPABASE_KEY, 'Authorization': 'Bearer ' + SUPABASE_KEY, 'Accept': 'application/json', 'Content-Type': 'application/json' };
        if (bodyStr) headers['Content-Length'] = Buffer.byteLength(bodyStr);
        if (extraHeaders) Object.assign(headers, extraHeaders);
        const req = httpModSb.request({ method, hostname: parsedSb.hostname, port: portSb, path, headers }, (res) => {
            let data = '';
            res.on('data', c => { data += c; });
            res.on('end', () => {
                let parsedBody;
                try { parsedBody = data ? JSON.parse(data) : null; } catch (e) { parsedBody = data; }
                resolve({ statusCode: res.statusCode, body: parsedBody });
            });
        });
        req.setTimeout(30000, () => { req.destroy(new Error('Supabase request timeout')); });
        req.on('error', reject);
        if (bodyStr) req.write(bodyStr);
        req.end();
    });
}

const CS_TOKEN = env.get('CLICKSIGN_TOKEN') || '';
const CS_BASE = 'https://app.clicksign.com';
const CS_PLACEHOLDER = !CS_TOKEN;

function csReq(method, path, bodyObj) {
    return new Promise((resolve, reject) => {
        const bodyStr = bodyObj ? JSON.stringify(bodyObj) : null;
        const headers = {
            'Authorization': CS_TOKEN,
            'Content-Type': 'application/vnd.api+json',
            'Accept': 'application/vnd.api+json'
        };
        if (bodyStr) headers['Content-Length'] = Buffer.byteLength(bodyStr);
        const req = nodeHttps.request({
            method, hostname: 'app.clicksign.com', port: 443,
            path: path, headers
        }, (res) => {
            let data = '';
            res.on('data', c => { data += c; });
            res.on('end', () => {
                let parsed;
                try { parsed = data ? JSON.parse(data) : null; } catch (e) { parsed = data; }
                resolve({ statusCode: res.statusCode, body: parsed });
            });
        });
        req.setTimeout(60000, () => { req.destroy(new Error('Clicksign request timeout')); });
        req.on('error', reject);
        if (bodyStr) req.write(bodyStr);
        req.end();
    });
}

const body = msg.payload || {};
const eventName = body.event && body.event.name;
const docInfo = body.document || {};
const documentId = docInfo.key || docInfo.id || null;
const envelopeInfo = body.envelope || {};

if (!eventName || !documentId) {
    node.warn('[cs-wh] Ignoring webhook: missing event.name or document.key');
    return null;
}

node.log('[cs-wh] Received event=' + eventName + ' doc=' + documentId);

// Helper: update comprovantes_de_pagamento by id_clicksign
async function updateComprovantes(filter, patch) {
    return pgReq('PATCH', '/rest/v1/comprovantes_de_pagamento?' + filter, patch, { 'Prefer': 'return=representation' });
}
async function updateRecibos(filter, patch) {
    return pgReq('PATCH', '/rest/v1/impressoes_de_recibo?' + filter, patch, { 'Prefer': 'return=representation' });
}

try {
    if (eventName === 'sign') {
        // Mark signed. Try both tables — whichever has the document id matching wins.
        const sigDatetime = new Date().toISOString();

        // Find signer email for user lookup (used as assinante_id on comprovantes)
        let signerEmail = null;
        if (docInfo.signers && Array.isArray(docInfo.signers) && docInfo.signers.length > 0) {
            signerEmail = docInfo.signers[0].email || null;
        }
        let assinanteId = null;
        if (signerEmail) {
            try {
                const userRes = await pgReq('GET', '/rest/v1/profiles?email=eq.' + encodeURIComponent(signerEmail) + '&select=id&limit=1', null);
                if (userRes.statusCode === 200 && Array.isArray(userRes.body) && userRes.body.length > 0) {
                    assinanteId = userRes.body[0].id;
                }
            } catch (ue) {
                node.warn('[cs-wh] profile lookup failed (non-fatal): ' + ue.message);
            }
        }

        // Update comprovantes
        const compPatch = { assinado: true, data_da_assinatura: sigDatetime };
        if (assinanteId) compPatch.assinante_id = assinanteId;
        const compRes = await updateComprovantes('id_clicksign=eq.' + encodeURIComponent(documentId), compPatch);
        const compUpdated = Array.isArray(compRes.body) ? compRes.body.length : 0;

        // Update recibos (538780001 = signed status code per PA)
        const recPatch = { signed_on_datetime: sigDatetime, situacao: 538780001 };
        const recRes = await updateRecibos('clicksign_document_id=eq.' + encodeURIComponent(documentId), recPatch);
        const recUpdated = Array.isArray(recRes.body) ? recRes.body.length : 0;

        node.log('[cs-wh] sign: comp_updated=' + compUpdated + ' rec_updated=' + recUpdated + ' doc=' + documentId);
        return null;
    }

    if (eventName === 'document_closed' || eventName === 'close' || eventName === 'auto_close') {
        // Download signed PDF → upload MinIO → update arquivo_s3_id/link
        const signedFileUrl = docInfo.downloads && docInfo.downloads.signed_file_url;
        const fileName = docInfo.filename || ('signed-' + documentId + '.pdf');
        if (!signedFileUrl) {
            node.warn('[cs-wh] document_closed without signed_file_url; skipping MinIO upload');
            return null;
        }

        // FIX H1 (SSRF): `signed_file_url` is attacker-controlled (webhook body, no HMAC
        // validation yet). Without an allowlist, a malicious actor could force this node
        // to GET internal services (Supabase at 192.168.25.40:8100, TrueNAS admin, etc.)
        // and potentially exfiltrate data via side-channels. Enforce hostname allowlist
        // matching Clicksign's known hosts. Subdomain matches allowed (e.g. any
        // `*.clicksign-production.s3.amazonaws.com`).
        const urlParsed = nodeUrl.parse(signedFileUrl);
        if (!urlParsed.protocol || !/^https?:$/.test(urlParsed.protocol)) {
            node.error('[cs-wh] SSRF blocked: invalid protocol ' + urlParsed.protocol + ' for doc=' + documentId);
            return null;
        }
        const allowedHosts = [
            'app.clicksign.com',
            's3.amazonaws.com',
            'clicksign.s3.amazonaws.com',
            'clicksign-documents.s3.amazonaws.com',
            'clicksign-production.s3.amazonaws.com'
        ];
        const host = urlParsed.hostname || '';
        const hostAllowed = allowedHosts.some(h => host === h || host.endsWith('.' + h));
        if (!host || !hostAllowed) {
            node.error('[cs-wh] SSRF blocked: untrusted host ' + host + ' for doc=' + documentId);
            return null;
        }

        // Download PDF
        const downloadMod = urlParsed.protocol === 'https:' ? nodeHttps : nodeHttp;
        const pdfBuf = await new Promise((resolve, reject) => {
            const req = downloadMod.get(signedFileUrl, (res) => {
                if (res.statusCode >= 300 && res.statusCode < 400 && res.headers.location) {
                    // Follow one redirect (also validated against allowlist for SSRF safety)
                    const redirUrl = res.headers.location;
                    const redirParsed = nodeUrl.parse(redirUrl);
                    const redirHost = redirParsed.hostname || '';
                    const redirAllowed = allowedHosts.some(h => redirHost === h || redirHost.endsWith('.' + h));
                    if (!redirHost || !redirAllowed || !/^https?:$/.test(redirParsed.protocol || '')) {
                        return reject(new Error('SSRF blocked on redirect: untrusted host ' + redirHost));
                    }
                    downloadMod.get(redirUrl, (res2) => {
                        const chunks = [];
                        res2.on('data', c => chunks.push(c));
                        res2.on('end', () => resolve(Buffer.concat(chunks)));
                        res2.on('error', reject);
                    }).on('error', reject);
                    return;
                }
                const chunks = [];
                res.on('data', c => chunks.push(c));
                res.on('end', () => resolve(Buffer.concat(chunks)));
                res.on('error', reject);
            });
            req.on('error', reject);
            req.setTimeout(60000, () => req.destroy(new Error('PDF download timeout')));
        });

        // Upload to MinIO (AWS SigV4)
        const MINIO_ENDPOINT = env.get('MINIO_ENDPOINT') || 'https://storage.unium.me';
        const ACCESS_KEY = env.get('MINIO_ACCESS_KEY') || '';
        const SECRET_KEY = env.get('MINIO_SECRET_KEY') || '';
        const CF_ID = env.get('CF_ACCESS_CLIENT_ID') || '';
        const CF_SEC = env.get('CF_ACCESS_CLIENT_SECRET') || '';
        const REGION = 'us-east-1';
        const bucket = 'pedidos';
        const safeKey = 'signed-' + documentId + '_' + fileName.replace(/[\/\\*?":<>|\x00-\x1f]/g, '_');
        // FIX L2: drop `.replace(/%20/g, '+')` — spaces should remain percent-encoded as %20
        // in S3 object keys for consistency (AWS SigV4 canonical URI and Supabase s3_objects.object_key).
        const objectKey = encodeURIComponent(safeKey);

        if (!ACCESS_KEY || !SECRET_KEY) {
            node.warn('[cs-wh] MinIO creds missing; skipping upload for doc=' + documentId);
            return null;
        }

        const endpointUrl = MINIO_ENDPOINT.replace(/\/$/, '');
        const parsedMinio = nodeUrl.parse(endpointUrl);
        function hmac(k, d, e) { return nodeCrypto.createHmac('sha256', k).update(d).digest(e || undefined); }
        function hashStr(d) { return nodeCrypto.createHash('sha256').update(d).digest('hex'); }
        const now = new Date();
        const amzDate = now.toISOString().replace(/[:-]/g, '').replace(/\.\d+/, '');
        const dateStamp = amzDate.slice(0, 8);
        const payloadHash = hashStr(pdfBuf);
        const canonicalUri = '/' + bucket + '/' + objectKey;
        const canonicalHeaders = [
            'content-type:application/pdf',
            'host:' + parsedMinio.host,
            'x-amz-content-sha256:' + payloadHash,
            'x-amz-date:' + amzDate
        ].join('\n') + '\n';
        const signedHeaders = 'content-type;host;x-amz-content-sha256;x-amz-date';
        const canonicalReq = ['PUT', canonicalUri, '', canonicalHeaders, signedHeaders, payloadHash].join('\n');
        const credScope = dateStamp + '/' + REGION + '/s3/aws4_request';
        const strToSign = ['AWS4-HMAC-SHA256', amzDate, credScope, hashStr(canonicalReq)].join('\n');
        const signKey = hmac(hmac(hmac(hmac('AWS4' + SECRET_KEY, dateStamp), REGION), 's3'), 'aws4_request');
        const signature = hmac(signKey, strToSign, 'hex');
        const authHeader = 'AWS4-HMAC-SHA256 Credential=' + ACCESS_KEY + '/' + credScope + ', SignedHeaders=' + signedHeaders + ', Signature=' + signature;

        const putOk = await new Promise((resolve) => {
            const req = nodeHttps.request({
                method: 'PUT',
                hostname: parsedMinio.hostname,
                port: parsedMinio.port || 443,
                path: canonicalUri,
                headers: {
                    'Authorization': authHeader,
                    'Content-Type': 'application/pdf',
                    'Content-Length': pdfBuf.length,
                    'x-amz-date': amzDate,
                    'x-amz-content-sha256': payloadHash,
                    'cf-access-client-id': CF_ID,
                    'cf-access-client-secret': CF_SEC
                }
            }, (res) => {
                let d = ''; res.on('data', c => { d += c; });
                res.on('end', () => resolve(res.statusCode === 200 || res.statusCode === 204));
            });
            req.on('error', (e) => { node.error('[cs-wh] MinIO PUT error: ' + e.message); resolve(false); });
            req.write(pdfBuf); req.end();
        });

        if (!putOk) {
            node.error('[cs-wh] MinIO upload failed for doc=' + documentId);
            return null;
        }

        // Insert s3_objects
        let s3ObjectsId = null;
        try {
            const sbInsRes = await pgReq('POST', '/rest/v1/s3_objects',
                { bucket_name: bucket, object_key: safeKey },
                { 'Prefer': 'return=representation' }
            );
            if (sbInsRes.statusCode >= 200 && sbInsRes.statusCode < 300 && Array.isArray(sbInsRes.body) && sbInsRes.body.length > 0) {
                s3ObjectsId = sbInsRes.body[0].id;
            }
        } catch (se) {
            node.warn('[cs-wh] s3_objects insert failed: ' + se.message);
        }

        const publicUrl = endpointUrl + '/' + bucket + '/' + objectKey;

        // Update comprovantes_de_pagamento
        const compPatch = { link_do_arquivo: publicUrl };
        if (s3ObjectsId) compPatch.arquivo_s3_id = s3ObjectsId;
        const compRes = await updateComprovantes('id_clicksign=eq.' + encodeURIComponent(documentId), compPatch);
        const compUpdated = Array.isArray(compRes.body) ? compRes.body.length : 0;

        // Update recibos (link_recibo + recibo_sharepoint_file_id replaced with public_url + s3_objects_id-ish mapping)
        const recPatch = { link_recibo: publicUrl };
        const recRes = await updateRecibos('clicksign_document_id=eq.' + encodeURIComponent(documentId), recPatch);
        const recUpdated = Array.isArray(recRes.body) ? recRes.body.length : 0;

        node.log('[cs-wh] document_closed: comp_updated=' + compUpdated + ' rec_updated=' + recUpdated + ' url=' + publicUrl);
        return null;
    }

    node.log('[cs-wh] Unhandled event=' + eventName + ' doc=' + documentId + ' (ignored)');
    return null;
} catch (e) {
    node.error('[cs-wh] Processor exception: ' + e.message);
    return null;
}

const errMsg = (msg.error && msg.error.message) || 'Unknown error';
node.warn('[cs-wh] CATCH: ' + errMsg);
// Webhook always returns 200; catch just logs.
return null;

const UUID_RE = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
function isUUID(v) { return typeof v === 'string' && UUID_RE.test(v); }
const EMAIL_RE = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
function isEmail(v) { return typeof v === 'string' && EMAIL_RE.test(v); }

const b = msg.payload || {};
const impressaoReciboId = String(b.impressaoReciboId || '').trim();
let pdfBase64 = String(b.pdfBase64 || '').trim();
const clienteNome = String(b.clienteNome || '').trim();
const clienteEmail = String(b.clienteEmail || '').trim();
const clienteTelefone = String(b.clienteTelefone || '').trim();
const signAuthType = b.signAuthType ? String(b.signAuthType).trim().toLowerCase() : 'whatsapp';
const documentName = b.documentName ? String(b.documentName).trim() : null;

if (!isUUID(impressaoReciboId)) {
    msg.statusCode = 400;
    msg.payload = { ok: false, error: 'impressaoReciboId must be a UUID' };
    return [null, msg];
}
if (!pdfBase64) {
    msg.statusCode = 400;
    msg.payload = { ok: false, error: 'pdfBase64 required' };
    return [null, msg];
}
if (pdfBase64.includes(',')) pdfBase64 = pdfBase64.split(',')[1];
// FIX M5: enforce 20MB limit in outer validator as defense-in-depth, using byte-length estimate
// (ceil(len * 3/4)) to avoid allocating a full Buffer from a potentially-100MB string.
// Core validator keeps an exact Buffer.byteLength check as second line of defense.
const pdfBytesEst = Math.ceil(pdfBase64.length * 3 / 4);
if (pdfBytesEst > 20 * 1024 * 1024) {
    msg.statusCode = 413;
    msg.payload = { ok: false, error: 'PDF exceeds 20 MB' };
    return [null, msg];
}
if (!clienteNome) {
    msg.statusCode = 400;
    msg.payload = { ok: false, error: 'clienteNome required' };
    return [null, msg];
}
if (!isEmail(clienteEmail)) {
    msg.statusCode = 400;
    msg.payload = { ok: false, error: 'clienteEmail invalid' };
    return [null, msg];
}
if (!clienteTelefone) {
    msg.statusCode = 400;
    msg.payload = { ok: false, error: 'clienteTelefone required' };
    return [null, msg];
}

msg._input = { impressaoReciboId, pdfBase64, clienteNome, clienteEmail, clienteTelefone, signAuthType, documentName };
return [msg, null];

const NR_ENV = env.get('NODE_RED_ENV') || 'prod';
if (NR_ENV !== 'prod') {
    msg.statusCode = 403;
    msg.payload = { ok: false, error: 'Blocked: not in prod environment' };
    return [null, msg];
}
return [msg, null];

const i = msg._input;
const ts = new Date().toISOString().replace(/[:.]/g, '-').slice(0, 19);
const docName = i.documentName || ('recibo-' + ts);
msg.payload = {
    documentName: docName,
    pdfBase64: i.pdfBase64,
    signerName: i.clienteNome,
    signerEmail: i.clienteEmail,
    signerPhone: i.clienteTelefone,
    signAuthType: i.signAuthType
};
msg._documentNameFinal = docName;
return msg;

const SUPABASE_URL = env.get('SUPABASE_URL') || '';
const SUPABASE_KEY = env.get('SUPABASE_SERVICE_ROLE_KEY') || '';
if (!SUPABASE_URL || !SUPABASE_KEY) {
    node.error('[clicksign] Missing Supabase env vars');
    msg.statusCode = 500;
    msg.payload = { ok: false, error: 'Server configuration error' };
    return [null, msg];
}
const parsedSb = nodeUrl.parse(SUPABASE_URL);
const isHttpsSb = parsedSb.protocol === 'https:';
const httpModSb = isHttpsSb ? nodeHttps : nodeHttp;
const portSb = parsedSb.port ? parseInt(parsedSb.port, 10) : (isHttpsSb ? 443 : 80);

function pgReq(method, path, bodyObj, extraHeaders) {
    return new Promise((resolve, reject) => {
        const bodyStr = bodyObj ? JSON.stringify(bodyObj) : null;
        const headers = { 'apikey': SUPABASE_KEY, 'Authorization': 'Bearer ' + SUPABASE_KEY, 'Accept': 'application/json', 'Content-Type': 'application/json' };
        if (bodyStr) headers['Content-Length'] = Buffer.byteLength(bodyStr);
        if (extraHeaders) Object.assign(headers, extraHeaders);
        const req = httpModSb.request({ method, hostname: parsedSb.hostname, port: portSb, path, headers }, (res) => {
            let data = '';
            res.on('data', c => { data += c; });
            res.on('end', () => {
                let parsedBody;
                try { parsedBody = data ? JSON.parse(data) : null; } catch (e) { parsedBody = data; }
                resolve({ statusCode: res.statusCode, body: parsedBody });
            });
        });
        req.setTimeout(30000, () => { req.destroy(new Error('Supabase request timeout')); });
        req.on('error', reject);
        if (bodyStr) req.write(bodyStr);
        req.end();
    });
}

const csResult = msg.payload || {};
if (!csResult.ok) {
    // Set situacao=538780003 (failed) per PA fallback
    const failPatch = { situacao: 538780003 };
    try {
        await pgReq('PATCH', '/rest/v1/impressoes_de_recibo?id=eq.' + encodeURIComponent(msg._input.impressaoReciboId), failPatch, { 'Prefer': 'return=representation' });
    } catch (fe) {
        node.warn('[cs-enviar-rec] Failed to mark recibo as failed: ' + fe.message);
    }
    msg.statusCode = 502;
    msg.payload = { ok: false, error: csResult.error || 'Clicksign core failed' };
    return [null, msg];
}

const i = msg._input;
const documentId = csResult.documentId;
const envelopeId = csResult.envelopeId;
const placeholder = !!csResult.csPlaceholder;

try {
    const patch = {
        clicksign_document_id: documentId,
        situacao: 538780000,  // signing-pending status
        telefone_para_envio: i.clienteTelefone,
        nome_cliente: i.clienteNome
    };
    const patchRes = await pgReq('PATCH', '/rest/v1/impressoes_de_recibo?id=eq.' + encodeURIComponent(i.impressaoReciboId), patch, { 'Prefer': 'return=representation' });
    if (patchRes.statusCode < 200 || patchRes.statusCode >= 300) {
        node.error('[cs-enviar-rec] Supabase patch failed HTTP ' + patchRes.statusCode + ' \u2014 ' + JSON.stringify(patchRes.body));
        msg.statusCode = 500;
        msg.payload = { ok: false, error: 'Failed to update recibo' };
        return [null, msg];
    }
    if (!Array.isArray(patchRes.body) || patchRes.body.length === 0) {
        msg.statusCode = 404;
        msg.payload = { ok: false, error: 'impressaoRecibo not found' };
        return [null, msg];
    }
    node.log('[cs-enviar-rec] SUCCESS rec=' + i.impressaoReciboId + ' doc=' + documentId + ' placeholder=' + placeholder);
    msg.statusCode = 200;
    msg.payload = {
        ok: true,
        impressaoReciboId: i.impressaoReciboId,
        documentId,
        envelopeId,
        csPlaceholder: placeholder
    };
    return [msg, null];
} catch (e) {
    node.error('[cs-enviar-rec] Exception: ' + e.message);
    msg.statusCode = 500;
    msg.payload = { ok: false, error: 'Internal error' };
    return [null, msg];
}

const errMsg = (msg.error && msg.error.message) || 'Unknown error';
node.warn('[cs-enviar-rec] CATCH: ' + errMsg);
msg.statusCode = msg.statusCode || 500;
msg.headers = { 'Content-Type': 'application/json', 'Cache-Control': 'no-store' };
msg.payload = { ok: false, error: 'Internal error' };
return msg;
